-- ── Quassel IRC ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, cross-platform IRC client built around a distributed core-and-client architecture, so your connection to IRC networks stays alive and your chat history persists even when your device is offline.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source under the GNU General Public License (GPL-2.0 and GPL-3.0); there are no paid tiers or commercial licenses.$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Volunteer open-source project maintained by the Quassel IRC Team, not a commercial company$q$, company_size),
  headquarters = COALESCE($q$No corporate headquarters - distributed open-source community project$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Czech$q$, $q$Finnish$q$]::text[],
  seo_title = COALESCE($q$Quassel IRC Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Everything you need to know about Quassel IRC, the free open-source always-on IRC client with a core-client architecture, before you install it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Quassel IRC is a free, open-source, cross-platform IRC client first introduced in 2008 and released under the GNU General Public License versions 2 and 3. It is developed and maintained by a volunteer community, the Quassel IRC Team, rather than a commercial company, and its source code is hosted publicly on GitHub. Quassel's defining architectural choice is a split between a lightweight core process and one or more client interfaces: the core maintains persistent connections to IRC networks, logs conversation history to a PostgreSQL or SQLite database, and keeps running whether or not a client is attached, while native Qt-based clients on Linux, macOS, and Windows (plus community mobile clients Quasseldroid for Android and iQuassel for iOS) can connect and disconnect from that core at any time without losing context, similar in spirit to running a text client inside screen or tmux but with a graphical interface. This means a user can close their laptop, reopen it hours later, and see the full conversation history that occurred while they were away, including messages from channels they were not actively viewing. Quassel supports simultaneous connections to multiple IRC networks, encrypted SSL connections between the core and its clients, customizable multi-identity management with per-network nicknames and away messages, command aliases, and proxy support. It became notable enough to be adopted as the default IRC client in Kubuntu starting with version 9.04 in 2009. The project has an active, if slower-paced, release cadence, with version 0.14.0 shipping January 1, 2022, and translation work maintained by community contributors into languages including German, French, Czech, and Finnish, with several other translations at varying levels of completeness. Because it is entirely free, open source, and self-hosted (users typically run the core themselves on a server, NAS, or always-on machine), Quassel has no company financials, funding, headquarters, or employee count to report; the project is sustained by contributor time rather than commercial revenue. It appeals most to technically comfortable IRC users, open-source community members, and system administrators who want an always-connected chat presence without paying for or relying on third-party IRC bouncer hosting services, and it is commonly compared to other IRC clients such as HexChat, irssi, and WeeChat, though Quassel is distinguished specifically by its built-in core-client split rather than requiring separate bouncer software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2fb7e2c0-a5af-47c6-b92d-1e035732d406';

