-- ── Quay ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Red Hat's container image registry, available as the hosted Quay.io service and as self-managed Red Hat Quay, providing secure image storage, vulnerability scanning, geo-replication, and automated builds for Docker and OCI images.$q$, short_description),
  pricing_model = COALESCE($q$Free for public repositories on Quay.io; paid tiers for private repositories on Quay.io; Red Hat Quay self-managed enterprise deployments are sold as a custom Red Hat subscription priced per deployment.$q$, pricing_model),
  starting_price = COALESCE($q$Free for public repositories; private repository and enterprise pricing not publicly disclosed - contact Red Hat sales$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$10,001+ employees (Red Hat, an IBM company)$q$, company_size),
  headquarters = COALESCE($q$Raleigh, North Carolina, USA (Red Hat headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Italian$q$, $q$Japanese$q$, $q$Korean$q$, $q$Portuguese$q$, $q$Simplified Chinese$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Red Hat Quay Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$A practical look at Red Hat Quay and Quay.io: container registry features, security scanning, pricing, and how it compares to other registries.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Quay is a container image registry that began in 2013 as an independent hosted service offering enterprise-grade features like image rollback and zero-downtime garbage collection, among the first hosted registries of its kind. In 2014 Quay was acquired by CoreOS, which used it as the foundation for an on-premise Quay Enterprise offering in addition to the hosted Quay.io service. When Red Hat acquired CoreOS in January 2018, Quay became part of Red Hat's product portfolio and was rebranded Red Hat Quay; Red Hat subsequently open-sourced the underlying technology as Project Quay. Today Quay exists in two closely related forms: Quay.io, a free public hosted registry (with paid tiers for private repositories) run by Red Hat, and Red Hat Quay, a self-managed, subscription-based enterprise registry that organizations deploy in their own infrastructure, often alongside Red Hat OpenShift and Kubernetes. Red Hat itself is headquartered in Raleigh, North Carolina, and operates as a subsidiary of IBM following IBM's 2019 acquisition of Red Hat, with Red Hat's global workforce numbering in the tens of thousands. Quay's core value proposition is security and operational control: it includes built-in vulnerability scanning (historically via the Clair scanner), fine-grained access control through robot accounts, detailed audit logging with rollback capability, automated image builds triggered by pushes to GitHub, GitLab, or Bitbucket, and high-availability geo-replication so a single registry can serve multiple data centers or cloud regions behind one URL. Red Hat Quay subscriptions are priced per deployment rather than per node, meaning a single registry installation using a shared data backend counts as one deployment regardless of how many pods or replicas run within it, and pricing is available in Standard and Premium support tiers through direct engagement with Red Hat sales rather than a public price list. Quay.io's public repositories remain free to use, making it a popular home for open-source project container images, while private repository pricing on Quay.io is tiered by the number of private repositories rather than by data volume or pull count. Quay is most commonly evaluated against other container registries such as Docker Hub, Amazon ECR, Azure Container Registry, Google Artifact Registry, and Harbor, and it is frequently chosen by organizations already invested in the Red Hat and OpenShift ecosystem or those with strict security, compliance, and image-scanning requirements.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd5332e67-88ad-4e34-998d-c503ab84ed89';

