-- ── QuestDB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$High-performance, open-source time-series database built for fast ingestion and low-latency SQL analytics on time-stamped data, commonly used for financial market data, IoT telemetry, and observability workloads.$q$, short_description),
  pricing_model = COALESCE($q$Open-core model: the self-hosted core database is free under the Apache 2.0 license; QuestDB Cloud is a usage-based managed offering, and QuestDB Enterprise is custom-priced self-hosted software with additional support and features.$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted); QuestDB Cloud starts at approximately 272 US dollars per month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom and New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$QuestDB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$An independent look at QuestDB, the open-source time-series database: architecture, features, pricing tiers, and how it compares to InfluxDB.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuestDB is an open-source time-series database designed for very fast data ingestion and low-latency SQL query performance on time-stamped data. The company behind it was founded in 2019 by Vlad Ilyushchenko, who serves as CTO and brings roughly two decades of experience building low-latency electronic trading platforms in FX, equities, and fixed income, and Nicolas Hourcard, CEO, who previously worked at Nasdaq and co-founded a Y Combinator open-source community initiative. QuestDB is a Y Combinator-backed company with dual headquarters in London, United Kingdom, and New York, United States, and it describes itself as a small, focused engineering team, generally estimated in the range of a few dozen employees. The company has raised approximately 15 million US dollars in venture funding, including a 12 million dollar Series A round announced in November 2021 with participation from investors such as Episode 1 Ventures, Uncorrelated Ventures, and 468 Capital. Technically, QuestDB uses a column-oriented storage engine with SIMD-vectorized query execution to achieve high throughput on both writes and reads, and it supports multiple ingestion protocols including the InfluxDB Line Protocol, the PostgreSQL wire protocol, and REST APIs, making it straightforward to plug into existing observability and IoT pipelines. The database extends standard SQL with time-series-specific functions such as SAMPLE BY for downsampling and LATEST ON for retrieving the most recent readings per series, and it supports open storage formats including Parquet alongside native integrations with tools like Grafana and Prometheus. QuestDB is distributed under the permissive Apache 2.0 license for its open-source core, which can be self-hosted at no cost. For teams that do not want to operate their own infrastructure, QuestDB Cloud offers a managed, usage-based hosted version starting at roughly 272 US dollars per month, while QuestDB Enterprise adds features aimed at larger organizations such as role-based access control, TLS encryption across all protocols, data compression, cold storage tiers, replication, and prioritized support, sold as custom-priced self-hosted software. QuestDB is most commonly compared to other time-series and analytical databases such as InfluxDB, TimescaleDB, and ClickHouse, and it is particularly popular among teams working with financial market tick data, industrial IoT sensor streams, and application performance monitoring or observability metrics where both high ingest rates and fast SQL analytics are required simultaneously.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8a1651b2-fc5c-4661-9e06-7316b78cb420';

