-- ── QuickBooks ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Intuit's QuickBooks accounting software brand, spanning the QuickBooks Desktop product line (Pro Plus, Premier Plus, and Enterprise) used by small and midsize businesses for bookkeeping, invoicing, payroll, and financial reporting.$q$, short_description),
  pricing_model = COALESCE($q$Annual desktop software subscriptions sold per license/user for QuickBooks Desktop products (Pro Plus, Premier Plus, Enterprise), separate from Intuit's cloud QuickBooks Online and QuickBooks Time monthly subscriptions.$q$, pricing_model),
  starting_price = COALESCE($q$From approximately 1,149 US dollars per year for QuickBooks Desktop Pro Plus (single user, as of February 2026 pricing)$q$, starting_price),
  founded_year = COALESCE(1992, founded_year),
  company_size = COALESCE($q$Approximately 18,200 employees (Intuit)$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, USA (Intuit headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$QuickBooks Review 2026: Desktop Pricing, Plans and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$An independent guide to the QuickBooks Desktop product line: Pro Plus, Premier Plus, and Enterprise pricing, features, and what replaced discontinued plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuickBooks is the accounting software brand created by Intuit, the financial software company founded in 1983 by Scott Cook and Tom Proulx and headquartered in Mountain View, California. QuickBooks itself launched in 1992 as a DOS-based small business accounting program, quickly followed by Windows and Mac versions, and by the mid-2000s it had come to dominate the small business accounting software market in the United States, reportedly holding around 74 percent market share by 2005 and roughly 94 percent by 2008. While the QuickBooks name today is most associated with the cloud-based QuickBooks Online product, the QuickBooks brand also encompasses the original QuickBooks Desktop product line, which remains in active use by many established small and midsize businesses and accounting firms, particularly those with complex, industry-specific, or highly customized bookkeeping workflows. The Desktop lineup historically included QuickBooks Pro, Premier, and Enterprise editions; Intuit stopped selling new QuickBooks Desktop Pro Plus, Premier Plus, and Mac Plus subscriptions to new customers after September 30, 2024, though existing subscribers can continue to renew their licenses. QuickBooks Enterprise remains open to new customers and is the only Desktop edition still actively sold to newcomers, though at a significantly higher price point that now includes a per-employee payroll fee. Desktop pricing rose sharply on February 1, 2026: single-user Pro Plus and Mac Plus increased from 999 to 1,149 US dollars per year, Premier Plus single-user pricing rose from 1,399 to 1,609 US dollars per year with additional multi-user seats increasing from 300 to 345 US dollars per user, and Enterprise pricing now starts around 2,210 US dollars per year for the Gold tier, roughly 2,717 US dollars per year for Platinum, and custom pricing above 4,200 US dollars per year, billed monthly, for the Diamond tier. Support timelines are also shifting: QuickBooks Desktop 2023 support ends May 31, 2026, after which payroll, bank feeds, and security updates stop functioning, while Desktop 2024 remains supported until September 30, 2027. Intuit, the parent company, employs roughly 18,200 people globally, operates more than 80 offices across 14 countries, and reported trailing twelve-month revenue of roughly 20.9 billion US dollars as of April 2026 across its full portfolio, which includes TurboTax, Credit Karma, QuickBooks, and Mailchimp in addition to QuickBooks. Intuit's active product development has clearly shifted toward QuickBooks Online, and Desktop customers are increasingly being encouraged to migrate to the cloud product, though Desktop editions, especially Enterprise, remain relevant for businesses with established desktop workflows, industry-specific edition needs (such as construction, manufacturing, retail, or nonprofit), or environments where a locally installed application is preferred over a browser-based tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
