-- ── QuickBooks Online ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Intuit's cloud-based accounting software for small and midsize businesses, offering invoicing, expense tracking, and financial reporting from any browser or the mobile app, sold in Solopreneur, Simple Start, Essentials, Plus, and Advanced tiers.$q$, short_description),
  pricing_model = COALESCE($q$Monthly SaaS subscription with five tiers scaling by features and user count, sold directly by Intuit with an introductory discount for new subscribers before standard pricing applies.$q$, pricing_model),
  starting_price = COALESCE($q$From 20 US dollars per month (Solopreneur); core QuickBooks Online plans start at 38 US dollars per month (Simple Start)$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$Approximately 18,200 employees (Intuit)$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, USA (Intuit headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$QuickBooks Online Pricing 2026: Plans, Tiers and What You Get$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare QuickBooks Online's Solopreneur, Simple Start, Essentials, Plus, and Advanced plans, current prices, and what each tier actually includes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuickBooks Online is Intuit's cloud-based, browser-accessible accounting software for small and midsize businesses, distinct from the locally installed QuickBooks Desktop product line. Intuit first launched a cloud version of QuickBooks in 2001 to offset declining packaged desktop software sales at brick-and-mortar retailers, though early versions were limited compared to the desktop product; QuickBooks Online was substantially rebuilt in 2013, which marked the real turning point in its adoption and functionality, and it has since become Intuit's primary focus for accounting product development, with QuickBooks Desktop Pro and Premier discontinued for new purchases after September 2024. QuickBooks Online is organized into five subscription tiers as of mid-2026: Solopreneur at 20 US dollars per month for freelancers and sole proprietors needing basic income, expense, and tax tracking; Simple Start at 38 US dollars per month, which adds full invoicing, sales tax automation, bill management, and 1099 contractor tracking for a single user; Essentials at 75 US dollars per month, which adds time tracking and supports up to three users; Plus at 115 US dollars per month, aimed at growing businesses that need inventory tracking, project profitability tracking, purchase orders, budgeting, and class or location tracking, supporting up to five users; and Advanced at 275 US dollars per month, designed for established small and midsize businesses needing more users, higher transaction volumes, complex custom reporting, and stronger internal controls. QuickBooks Online has a history of raising prices roughly once a year, typically during the summer, with recent increases in the range of 12 to 17 percent annually since 2023; new subscribers typically receive an introductory discounted rate locked in for the first several months before standard pricing applies. As a division of Intuit, which is headquartered in Mountain View, California, and employs roughly 18,200 people globally with more than 80 offices across 14 countries, QuickBooks Online benefits from Intuit's broader financial technology ecosystem, including integrated payroll, payments, and third-party app marketplace connections, and it is by far the most widely used cloud accounting platform among small businesses in the United States. It is most commonly compared to competing cloud accounting products such as Xero, FreshBooks, and Wave, and it is generally chosen over QuickBooks Desktop by businesses that want anywhere, any-device access, automatic updates, and continuous feature development rather than a periodically upgraded locally installed application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9e200cb1-a048-4c0a-ac15-ece1a517f982';

