-- ── QuickBooks Time ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Intuit's employee time tracking and workforce scheduling product, formerly known as TSheets, offering GPS-enabled mobile time tracking, scheduling, and project time reporting that integrates with QuickBooks Online and QuickBooks Payroll.$q$, short_description),
  pricing_model = COALESCE($q$Monthly subscription with a flat base fee plus a per-active-user monthly fee, offered in two tiers (Premium and Elite); a QuickBooks Online subscription is required to use it.$q$, pricing_model),
  starting_price = COALESCE($q$From 20 US dollars per month base fee plus 10 US dollars per user per month (Premium plan, current 2026 pricing)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$Approximately 18,200 employees (Intuit); originally an independent company before its 2018 acquisition$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, USA (Intuit headquarters); product originated in Boise/Eagle, Idaho as TSheets$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$QuickBooks Time Pricing 2026: Premium vs Elite Plans Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Understand QuickBooks Time's current pricing, Premium versus Elite features, and how the former TSheets product fits with QuickBooks Online.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuickBooks Time is Intuit's dedicated employee time tracking and scheduling product, previously known as TSheets before its rebrand. TSheets was founded in 2006 in Eagle, Idaho by CEO Matt Rissell after he identified a gap in the employee time tracking and reporting market, and it grew into a substantial independent time-tracking software company before Intuit announced its acquisition on December 5, 2017, in a deal valued at approximately 340 million US dollars in cash and other consideration; the acquisition closed on January 11, 2018. Following the acquisition, the Eagle/Boise-based company was integrated into Intuit, its offices rebranded as an Intuit site, and the product was gradually renamed from TSheets by QuickBooks to its current name, QuickBooks Time. As a product line within Intuit, which is headquartered in Mountain View, California, and employs roughly 18,200 people globally, QuickBooks Time does not have separate public company financials, though it continues to power time tracking for a large share of QuickBooks Online's small business customer base. QuickBooks Time offers GPS-enabled mobile time tracking so employees can clock in and out from job sites, along with scheduling tools for creating and sharing employee schedules, geofencing to prompt clock-in and clock-out reminders based on location, overtime alerts, and reporting that feeds directly into QuickBooks Online and QuickBooks Payroll for streamlined payroll processing. The product is sold in two tiers: Premium, aimed at companies primarily focused on tracking attendance and basic scheduling, and Elite, aimed at companies that need more advanced project time tracking, real-time project collaboration, and geofencing precision. As of the 2026 pricing structure, Premium costs 20 US dollars per month as a flat base fee plus 10 US dollars per active user per month, while Elite costs 40 US dollars per month as a base fee plus 12 US dollars per active user per month; both figures reflect a price increase implemented on approximately July 1, 2026, which raised the previous per-user rates by roughly 2 US dollars per user across both tiers, a change reported as roughly a 25 percent increase for the Premium tier's per-user fee. Both plans include one free admin license, and a QuickBooks Online subscription is required to use QuickBooks Time, since the two products are designed to work together rather than as fully independent purchases. QuickBooks Time is most commonly compared to standalone time tracking and workforce management tools such as When I Work, Homebase, Deputy, and Toggl Track, and its primary advantage over those competitors is its native, tight integration with QuickBooks Online and QuickBooks Payroll for businesses already using Intuit's accounting ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b5f7e26c-b483-4bd7-8ac4-22126346a402';

