INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Full session replay$q$, $q$DOM-accurate reconstruction of real user sessions across web and mobile so teams can see exactly what a customer experienced, not just aggregate metrics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Journey and funnel analytics$q$, $q$Visualizes how users move through key flows and where they drop off, tying friction directly to conversion and revenue impact.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Automated anomaly and friction detection$q$, $q$Surfaces issues like rage clicks, error states, and abandoned forms automatically instead of requiring manual session review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Felix agentic AI$q$, $q$AI-driven Analyst, Agent, and Partner modes that summarize sessions, surface insights, and can recommend or take action on identified issues.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Real-time data activation$q$, $q$Pushes Quantum Metric insights and events into other business systems in real time to trigger downstream workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Employee experience monitoring$q$, $q$Extends the same session-level analytics approach to internal, employee-facing applications as an add-on.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Contact center integration$q$, $q$Connects digital session data with contact center interactions to help support teams resolve issues faster with full context.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Data warehouse streaming$q$, $q$Streams raw Quantum Metric data into customer-owned data warehouses for custom analysis alongside other business data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Very deep, DOM-accurate session replay combined with quantified behavioral data in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Enterprise-grade scalability suited to very high session volumes and many digital properties$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Felix AI features reduce manual analysis time by auto-surfacing anomalies and insights$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Strong fit for regulated, high-traffic industries like retail, travel, and financial services$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Real-time data activation lets other systems react to Quantum Metric findings automatically$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Recognized as a strong workplace and well regarded in enterprise analyst and review platforms$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$No published pricing; every deal requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Cost and scope generally make it impractical for small businesses or low-traffic sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Implementation and tagging setup can take meaningful time before value is realized$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Feature depth creates a learning curve for teams new to session-replay-driven analytics$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Some advanced capabilities like employee experience or contact center integration are paid add-ons$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Best suited to organizations that already have dedicated product or UX analytics teams$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$What is Quantum Metric used for$q$, $q$Quantum Metric is used by enterprises to combine quantitative analytics with session replay so product, UX, and engineering teams can identify and quantify friction in digital experiences and prioritize fixes by business impact.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$How much does Quantum Metric cost$q$, $q$Quantum Metric does not publish pricing. Cost is custom and depends on the number of digital properties monitored, session and data volume, and the service level included in the contract.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Who founded Quantum Metric$q$, $q$Quantum Metric was founded in 2015 by Mario Ciabarra and is headquartered in Colorado Springs, Colorado.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$What is Felix in Quantum Metric$q$, $q$Felix is Quantum Metric's agentic AI layer, offering Analyst mode for automated insight summarization, Agent mode for taking or recommending action, and Partner mode for deeper collaborative analysis.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Is Quantum Metric a unicorn company$q$, $q$Yes. Quantum Metric raised a 200 million dollar Series B round in January 2021 that valued the company above 1 billion dollars, and it has raised roughly 250 million dollars in total disclosed funding.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$How is Quantum Metric different from Google Analytics$q$, $q$Quantum Metric focuses on session-level replay and quantified friction detection for enterprise product and UX teams, whereas Google Analytics is primarily a traffic and marketing analytics tool without native full session replay.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Does Quantum Metric require developer implementation$q$, $q$Yes, initial setup typically involves tagging digital properties and configuring PII redaction, and Quantum Metric's team provides implementation support as part of enterprise contracts.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Is there a free trial of Quantum Metric$q$, $q$Quantum Metric is sold through a sales-led enterprise process rather than public self-serve signup, so prospective customers should contact sales to discuss a trial or proof of concept.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Ecommerce conversion optimization$q$, $q$Retail and ecommerce teams use session replay and journey analytics to find and fix checkout friction, abandoned carts, and broken flows that suppress conversion.$q$, $q$Ecommerce product managers and conversion rate optimization teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Enterprise UX and product friction remediation$q$, $q$Large product organizations use quantified friction detection to prioritize engineering fixes based on measurable revenue and experience impact rather than anecdote.$q$, $q$Product managers, UX researchers, and engineering leads at large enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Customer support and contact center troubleshooting$q$, $q$Support teams use session replay tied to contact center interactions to quickly understand what a customer experienced before escalating or resolving an issue.$q$, $q$Customer support and contact center operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$Enterprise (Custom)$q$, $q$Custom - contact sales$q$, $q$Annual contract$q$, NULL, $q$["Full session replay and journey analytics","Anomaly and friction detection","Felix AI Analyst, Agent, and Partner modes","Real-time data activation","Implementation and PII remediation support","Optional add-ons: employee experience monitoring, data enrichment, contact center integration, data warehouse streaming"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quantum Metric is an enterprise-grade digital experience analytics platform that unifies quantitative behavioral data with qualitative session replay so that product, UX, engineering, and business teams can work from a single, quantified view of the customer experience. Founded in 2015 by Mario Ciabarra and based in Colorado Springs, Colorado, the company built its platform around the idea that most organizations struggle because different teams measure success with different, disconnected tools.$q$, $q$Since reaching a valuation above 1 billion dollars in 2021, Quantum Metric has expanded from a pure analytics and replay tool into what it now calls a continuous product design platform, adding agentic AI capabilities under the Felix brand that summarize sessions, surface anomalies automatically, and recommend or trigger actions across connected systems. The platform is aimed squarely at large enterprises running high-traffic digital properties where even small conversion or performance issues carry significant revenue impact.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Quantum Metric captures full, DOM-accurate session replay alongside structured behavioral data, letting teams both watch exactly what a user experienced and quantify how common or costly that experience was across the whole user base. Journey and funnel visualization, interaction heatmaps, and automated anomaly detection help teams spot friction points such as rage clicks, form abandonment, or error states without manually reviewing thousands of sessions.$q$, $q$The Felix AI layer adds an Analyst mode that automatically summarizes patterns across sessions, an Agent mode that can act on identified issues, and a Partner mode intended for deeper collaborative investigation. Additional capabilities include real-time data activation to downstream systems, PII redaction during implementation, employee experience monitoring, contact center integrations, and data streaming to customer-owned data warehouses for teams that want to combine Quantum Metric data with their own analytics infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('546750c3-813f-430c-a551-e76c5f6484f1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Quantum Metric does not publish self-serve pricing tiers or a starting price. Instead, every customer receives a custom quote based on the number of websites, mobile apps, and other digital properties they want monitored, the volume of session and event data collected, and the level of customer success and professional services bundled into the contract.$q$, $q$This enterprise sales-led pricing model is typical of large-scale digital experience and session replay platforms and reflects Quantum Metric's focus on large organizations rather than small businesses or individual developers. Prospective buyers should expect a scoping conversation with the Quantum Metric sales team, and total cost can vary significantly depending on traffic volume, number of properties, data retention needs, and optional add-ons like employee experience monitoring or contact center integration.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Core-client architecture$q$, $q$A persistent core maintains IRC connections and history independently of any connected client, so nothing is lost when you disconnect.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Multi-network support$q$, $q$Connect to and manage multiple IRC networks simultaneously from a single core and interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Persistent chat history$q$, $q$Conversation logs are stored in a PostgreSQL or SQLite database on the core, available whenever you reconnect.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Cross-platform native clients$q$, $q$Native Qt-based clients for Linux, macOS, and Windows, plus community mobile apps Quasseldroid and iQuassel.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Encrypted core-client connections$q$, $q$SSL encryption secures the link between the core and any client connecting to it.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Multi-identity management$q$, $q$Configure distinct nicknames, away messages, and identities per network or channel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Command aliases and proxy support$q$, $q$Streamline repetitive IRC commands and connect through network proxies when needed.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Open-source and free forever$q$, $q$Released under GPL-2.0 and GPL-3.0, with publicly available source code and no licensing cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Always-on core keeps chat history and presence intact across disconnects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Supports many simultaneous IRC network connections$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Native cross-platform clients plus community mobile apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$SSL-encrypted core-client connections for security$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Long-standing project with a stable, established codebase$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Requires running and maintaining a core process on an always-on machine or server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Development pace has slowed, with the last major release in January 2022$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Setup is more involved than single-binary IRC clients for newcomers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$User interface feels dated compared to modern chat applications$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Mobile clients are community-maintained rather than official first-party apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$No built-in support for chat protocols beyond IRC$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Is Quassel IRC free$q$, $q$Yes. Quassel IRC is completely free and released under the GNU General Public License versions 2 and 3, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$What platforms does Quassel support$q$, $q$Quassel has native clients for Linux, macOS, and Windows, plus community-maintained mobile clients Quasseldroid for Android and iQuassel for iOS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$What is the core-client architecture in Quassel$q$, $q$Quassel splits into a persistent core that maintains IRC connections and stores history, and separate clients that can connect or disconnect from that core at any time without losing chat state.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Is there a mobile app for Quassel$q$, $q$Yes, community-maintained mobile clients exist: Quasseldroid for Android and iQuassel for iOS, both of which connect to a Quassel core.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Is Quassel IRC still maintained$q$, $q$Quassel is an active open-source project with a volunteer maintainer team, though its release cadence has slowed, with version 0.14.0 released in January 2022 as the most recent major version.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$What license does Quassel use$q$, $q$Quassel is released under the GNU General Public License, dual-licensed as GPL-2.0-only or GPL-3.0-only.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$How is Quassel different from other IRC clients like HexChat$q$, $q$Unlike single-process clients such as HexChat, Quassel separates a persistent core from the client interface, so your IRC connection and history survive even when no client is attached, without needing separate bouncer software.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Do I need to run my own server to use Quassel$q$, $q$Yes, Quassel requires running the core component somewhere that stays online, such as a personal server, NAS, or VPS, in addition to installing a client to connect to it.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Always-connected IRC for open-source communities$q$, $q$Developers and maintainers who participate in project IRC channels use Quassel to stay continuously connected and never miss discussion, even when switching devices.$q$, $q$Open-source contributors and maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Self-hosted alternative to bouncer-plus-client setups$q$, $q$Users who previously ran a terminal client inside screen or tmux with a separate IRC bouncer use Quassel to get the same always-on behavior with a graphical interface built in.$q$, $q$Linux and Unix power users and system administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Small team internal chat over IRC$q$, $q$Small technical teams that standardize on IRC for internal communication use Quassel so team members share a persistent, synchronized view of channel history.$q$, $q$Small technical teams and hobbyist communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core and client software","Unlimited IRC network connections","Self-hosted core with no usage limits","Community support via project resources","Source code access under GPL"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quassel IRC is a free and open-source IRC client introduced in 2008 that solves a long-standing IRC problem: staying connected and not missing messages when you close your laptop or switch devices. It does this through a core-and-client architecture, where a persistent core process maintains your IRC network connections and stores chat history in a PostgreSQL or SQLite database, while separate graphical clients built with the Qt framework connect to that core whenever you want to read or send messages.$q$, $q$Because the core keeps running independently, Quassel behaves similarly to pairing a terminal multiplexer with a text-based IRC client, but with a full graphical interface and native apps for Linux, macOS, and Windows, along with community-maintained mobile clients for Android and iOS. The project is maintained entirely by volunteer contributors under the GPL and has no commercial entity, pricing, or company behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Quassel supports simultaneous connections to multiple IRC networks from a single core, SSL-encrypted connections between the core and any attached clients, and flexible multi-identity management so users can present different nicknames or away messages on different networks. Chat history is retained in the core's database, meaning conversations that happened while no client was connected are still available once you reconnect.$q$, $q$Additional conveniences include command aliases for frequently used IRC commands, proxy support for connecting through restricted networks, and a native, customizable Qt-based interface. The core-client split also means a single core installation can serve multiple client devices, so a user can pick up the same synchronized conversation on a desktop client and a mobile client without losing scrollback or state.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Quassel IRC is entirely free. It is distributed under the GNU General Public License version 2 and version 3, which means the source code is open, redistribution and modification are permitted under the license terms, and there is no cost to download, install, or use the software.$q$, $q$There are no premium tiers, subscriptions, or paid add-ons. Running Quassel does typically require hosting the core process somewhere that stays online, such as a personal server, always-on desktop, or virtual private server, which may carry hosting costs, but those costs are unrelated to the Quassel software itself, which remains free regardless of deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2fb7e2c0-a5af-47c6-b92d-1e035732d406', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Built-in vulnerability scanning$q$, $q$Automatically scans container images for known vulnerabilities to help teams catch security issues before deployment.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Robot accounts and access control$q$, $q$Fine-grained, auditable access delegation designed for automated systems and CI/CD pipelines rather than human logins.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Automated build triggers$q$, $q$Builds and publishes new container images automatically in response to pushes from GitHub, GitLab, or Bitbucket.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Audit logging and rollback$q$, $q$Maintains an easy-to-audit history of registry changes with the ability to roll back to previous states.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$High availability and geo-replication$q$, $q$Runs multiple registry instances across data centers or cloud regions behind a single URL for resilience and low-latency access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Free public repositories on Quay.io$q$, $q$Hosts public container images at no cost, widely used by open-source projects for image distribution.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$OCI and Docker image support$q$, $q$Compatible with both Docker and Open Container Initiative image formats for broad tooling compatibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Kubernetes and OpenShift integration$q$, $q$Integrates closely with Kubernetes and Red Hat OpenShift for enterprise container platform workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Strong built-in security scanning and audit logging out of the box$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Proven at enterprise scale with roots in CoreOS and Red Hat engineering$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Flexible deployment as either hosted Quay.io or self-managed Red Hat Quay$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Free hosting for public repositories benefits open-source projects$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Solid geo-replication and high-availability options for global deployments$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Deep integration with Kubernetes and OpenShift environments$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Enterprise and private repository pricing is not publicly transparent$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Self-managed deployment and sizing can require significant operational expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Smaller community mindshare compared to Docker Hub for general-purpose use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Some advanced features are gated behind a paid Red Hat subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Learning curve for configuring full RBAC and geo-replication correctly$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Pricing model per deployment can be less intuitive than simple per-seat pricing$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$What is the difference between Quay.io and Red Hat Quay$q$, $q$Quay.io is Red Hat's publicly hosted registry service, free for public repositories with paid tiers for private ones, while Red Hat Quay is the self-managed, subscription-based version organizations deploy in their own infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Is Quay free to use$q$, $q$Public repositories on Quay.io are free. Private repositories on Quay.io require a paid plan, and self-managed Red Hat Quay requires a Red Hat subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Who owns Quay$q$, $q$Quay is owned by Red Hat, which itself is a subsidiary of IBM. Quay was originally an independent product acquired by CoreOS in 2014, then became part of Red Hat when Red Hat acquired CoreOS in 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Does Quay support Kubernetes$q$, $q$Yes, Quay integrates closely with Kubernetes and is commonly deployed alongside Red Hat OpenShift as the container image registry for Kubernetes-based platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$What is Project Quay$q$, $q$Project Quay is the open-source upstream project that Red Hat released, forming the technical foundation for both the hosted Quay.io service and the commercial Red Hat Quay product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Does Quay scan images for vulnerabilities$q$, $q$Yes, Quay includes built-in container image vulnerability scanning as a core security feature.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Can I self-host Quay$q$, $q$Yes, Red Hat Quay can be self-hosted in your own infrastructure as a subscription product, separate from the publicly hosted Quay.io service.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Secure enterprise container registry$q$, $q$Regulated organizations use Red Hat Quay's vulnerability scanning, audit logging, and access control to meet compliance requirements for container image supply chains.$q$, $q$Enterprise platform and security engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Multi-region container distribution$q$, $q$Global organizations use Quay's geo-replication to serve container images with low latency to Kubernetes and OpenShift clusters across multiple regions.$q$, $q$Platform engineers running multi-region Kubernetes or OpenShift fleets$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Free public image hosting for open-source projects$q$, $q$Open-source maintainers use Quay.io to host and distribute public container images at no cost to their user community.$q$, $q$Open-source project maintainers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Quay.io Public Repositories$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited public repository hosting","Basic vulnerability scanning","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Quay.io Private Repositories$q$, $q$Not publicly disclosed - tiered by number of private repositories$q$, $q$Monthly or annual$q$, NULL, $q$["Private repository hosting","Vulnerability scanning","Robot accounts and access control"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$Red Hat Quay Enterprise$q$, $q$Custom - contact Red Hat sales$q$, $q$Annual subscription, priced per deployment$q$, NULL, $q$["Self-managed deployment","High availability and geo-replication","Standard or Premium support","Unlimited pods per deployment","Advanced RBAC and audit logging"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quay is a container image registry with roots going back to 2013, when it launched as one of the first hosted enterprise container registries, offering features like image rollback and zero-downtime garbage collection before container registries were common. CoreOS acquired Quay in 2014 and built an on-premise Quay Enterprise offering around it, and when Red Hat acquired CoreOS in January 2018, Quay became a core part of Red Hat's cloud and container portfolio under the name Red Hat Quay.$q$, $q$Red Hat later open-sourced the underlying technology as Project Quay, and the product now exists in two forms: the publicly hosted Quay.io service, which is free for public repositories, and self-managed Red Hat Quay, a subscription product that organizations deploy in their own environments, frequently alongside Red Hat OpenShift and other Kubernetes distributions for enterprise-grade security and control over container image supply chains.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Quay's security-first design includes built-in vulnerability scanning of container images, fine-grained access control through robot accounts intended for automated systems, and detailed audit logging that supports rolling back changes when something goes wrong. Automated build triggers connect directly to GitHub, GitLab, and Bitbucket so new image versions can be built and published automatically whenever code is pushed.$q$, $q$For organizations operating at scale, Red Hat Quay supports high availability and geo-replication, allowing a single logical registry to run across multiple data centers or cloud regions behind one URL, which is particularly valuable for globally distributed Kubernetes and OpenShift deployments. Quay supports both Docker and OCI image formats and integrates tightly with the broader Red Hat and Kubernetes ecosystem.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5332e67-88ad-4e34-998d-c503ab84ed89', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Public repositories on Quay.io are free to host and use, which is why many open-source projects rely on it for distributing container images at no cost. Private repositories on Quay.io are sold in tiered plans based on the number of private repositories rather than data volume, though Red Hat does not publish a fixed price list for these tiers.$q$, $q$Self-managed Red Hat Quay for enterprise deployments is sold as a Red Hat subscription priced per deployment, where a deployment refers to a single registry installation using a shared data backend, with no limit on the number of pods that can be run within that deployment. Subscriptions are available at Standard or Premium support levels, and exact pricing requires contacting Red Hat sales for a quote based on deployment scope and support needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Column-oriented storage engine$q$, $q$Optimized for time-series workloads with fast writes and efficient scans across large historical datasets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$SIMD-vectorized query execution$q$, $q$Uses vectorized processing to accelerate SQL query performance on large volumes of time-stamped data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Multiple ingestion protocols$q$, $q$Supports InfluxDB Line Protocol, PostgreSQL wire protocol, and REST APIs for flexible data ingestion.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Time-series SQL extensions$q$, $q$Adds functions like SAMPLE BY and LATEST ON to standard SQL for downsampling and retrieving latest readings per series.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Open storage format support$q$, $q$Works with open formats such as Parquet, avoiding vendor lock-in for stored data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Native observability integrations$q$, $q$Connects directly with tools like Grafana and Prometheus for dashboards and monitoring.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$QuestDB Enterprise security features$q$, $q$Adds role-based access control, TLS encryption across all protocols, and data compression for larger deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$High availability and replication$q$, $q$Enterprise tier supports replication and cold storage tiering for resilience and cost-efficient long-term retention.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Very fast ingestion and query performance for time-series-specific workloads$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Free and open source under the permissive Apache 2.0 license$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$SQL-native interface lowers the learning curve for existing SQL users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Supports multiple ingestion protocols for easy integration into existing pipelines$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Backed by Y Combinator and an experienced founding team from trading and Nasdaq backgrounds$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Active open-source community and public GitHub development$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Smaller plugin and integration ecosystem compared to established players like InfluxDB or TimescaleDB$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Enterprise features such as HA, RBAC, and replication require a paid tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$QuestDB Cloud pricing beyond the starting tier requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Best suited specifically to time-series workloads rather than general-purpose relational use$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Small company size relative to larger established database vendors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Documentation and community resources are still maturing compared to older databases$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Is QuestDB free$q$, $q$Yes, the core QuestDB database is open source under the Apache 2.0 license and free to self-host. QuestDB Cloud and QuestDB Enterprise are paid managed and enterprise offerings respectively.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$What is QuestDB used for$q$, $q$QuestDB is used for time-series workloads that need fast ingestion and low-latency SQL queries, such as financial market data, IoT sensor telemetry, and application observability metrics.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Who created QuestDB$q$, $q$QuestDB was founded in 2019 by Vlad Ilyushchenko (CTO) and Nicolas Hourcard (CEO), and the company is backed by Y Combinator.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$What license does QuestDB use$q$, $q$QuestDB's open-source core is released under the Apache 2.0 license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$How does QuestDB compare to InfluxDB$q$, $q$Both are time-series databases, but QuestDB emphasizes a standard SQL interface with time-series extensions and column-oriented, SIMD-accelerated query execution, while InfluxDB uses its own query languages and storage engine.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Does QuestDB support SQL$q$, $q$Yes, QuestDB uses standard SQL extended with time-series-specific functions like SAMPLE BY and LATEST ON.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Is there a managed cloud option for QuestDB$q$, $q$Yes, QuestDB Cloud is a managed, usage-based hosted version of QuestDB starting at approximately 272 US dollars per month.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Financial market data storage and analysis$q$, $q$Trading firms and fintech companies use QuestDB to store and query high-frequency tick data with the low latency required for trading and risk systems.$q$, $q$Quantitative trading and fintech engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$IoT and industrial telemetry$q$, $q$Industrial and IoT companies use QuestDB to ingest and analyze large volumes of sensor data from connected devices in near real time.$q$, $q$IoT platform and industrial engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Application performance monitoring and observability$q$, $q$Engineering teams use QuestDB to store and query high-cardinality metrics for monitoring application and infrastructure performance.$q$, $q$DevOps, SRE, and observability engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted single-node deployment","Full SQL query engine with time-series extensions","Apache 2.0 licensed source code","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$QuestDB Cloud$q$, $q$From approximately 272 US dollars per month$q$, $q$Monthly, usage-based$q$, NULL, $q$["Fully managed hosting","Automatic scaling by instance size","Usage-based billing","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$QuestDB Enterprise$q$, $q$Custom - contact sales$q$, $q$Annual subscription$q$, NULL, $q$["Self-hosted deployment","Role-based access control","TLS across all protocols","Data compression and cold storage","Replication and high availability","Prioritized support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuestDB is an open-source time-series database purpose-built for workloads that generate enormous volumes of time-stamped data and need both extremely fast ingestion and low-latency SQL analytics, such as financial market data, industrial sensor telemetry, and application observability metrics. The company was founded in 2019 by Vlad Ilyushchenko, whose background is in building low-latency electronic trading systems, and Nicolas Hourcard, formerly of Nasdaq, and it operates as a Y Combinator-backed startup with headquarters spanning London and New York.$q$, $q$QuestDB's core differentiator is combining the raw ingest and query performance associated with specialized time-series engines with a familiar, standard SQL interface extended with time-series-specific functions, so teams do not need to learn a proprietary query language to get the performance benefits of a purpose-built engine.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Under the hood, QuestDB uses a column-oriented storage engine paired with SIMD-vectorized query execution to process large volumes of data quickly, and it supports flexible ingestion through the InfluxDB Line Protocol, the PostgreSQL wire protocol, and REST endpoints, so it can slot into existing data pipelines without requiring a proprietary client.$q$, $q$QuestDB extends SQL with time-series-native functions like SAMPLE BY for time-bucketed aggregation and LATEST ON for retrieving the most recent value per series, and it supports open data formats such as Parquet alongside native integrations with common observability tools like Grafana and Prometheus. QuestDB Enterprise builds on the open-source core with role-based access control, TLS everywhere, data compression, cold storage tiering, and replication for organizations with stricter operational and compliance requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The QuestDB core database is fully open source under the Apache 2.0 license and free to self-host, with no artificial feature limits placed on the open-source version for single-node deployments. This makes it accessible to individual developers and teams who are comfortable managing their own infrastructure.$q$, $q$For teams that prefer a managed service, QuestDB Cloud is a usage-based hosted offering that starts at approximately 272 US dollars per month depending on instance size and usage. Organizations with larger-scale or compliance-driven needs can opt for QuestDB Enterprise, a custom-priced self-hosted subscription that adds high availability, RBAC, TLS across all protocols, and dedicated support, with exact pricing available directly from QuestDB.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a1651b2-fc5c-4661-9e06-7316b78cb420', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Drag-and-drop survey builder$q$, $q$Create surveys with more than 40 question types, branching, and skip logic without needing technical skills.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Multilingual survey and platform support$q$, $q$Interface localized in 230-plus languages, with survey content translatable into roughly 90-95 languages including right-to-left scripts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Offline data collection$q$, $q$Collect survey responses in the field without an internet connection, syncing data once reconnected.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Advanced analytics and reporting$q$, $q$Cross-tabulation, dashboards, and advanced statistical analysis tools for turning responses into insights.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$CX and Net Promoter Score suite$q$, $q$Dedicated customer experience tools for tracking NPS, satisfaction, and customer journey feedback.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Employee experience and workforce surveys$q$, $q$Purpose-built tools for engagement, pulse, and workforce feedback surveys aimed at HR teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Market research and panel management$q$, $q$Research Suite tools for managing research panels and running structured market research studies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Academic and non-profit discounts$q$, $q$Reduced pricing available for qualifying academic institutions and non-profit organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Generous free Essentials plan compared to many competing survey tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Extensive multilingual support across both platform interface and survey content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Specialized suites for CX, workforce, and market research beyond basic surveys$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Strong offline data collection for field research use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Deep cross-tabulation and advanced reporting capabilities$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Academic and non-profit discount pricing available$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Per-user pricing can become costly for larger survey teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Breadth of features can feel complex for first-time or casual users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Some advanced capabilities are reserved for enterprise suites rather than core plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Enterprise suite pricing is not publicly listed and requires a sales quote$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Team Edition pricing requires a minimum of five users to access$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Is QuestionPro free$q$, $q$Yes, QuestionPro offers a free Essentials plan for individuals and small projects, in addition to paid per-user plans and custom enterprise suites.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Where is QuestionPro headquartered$q$, $q$QuestionPro is headquartered in Austin, Texas, after relocating from San Francisco in 2020; the company was originally founded in Seattle in 2005.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$What is the difference between QuestionPro Essentials and Team Edition$q$, $q$Essentials is a free plan aimed at individuals and small projects, while Team Edition is a paid, per-user plan starting around 83 US dollars per user per month billed annually, aimed at teams of five or more users with added collaboration and reporting features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Does QuestionPro support multiple languages$q$, $q$Yes, the QuestionPro platform interface is localized into more than 230 languages, and survey content can be translated and collected in roughly 90 to 95 languages, including right-to-left and multi-byte character languages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$What is QuestionPro CX$q$, $q$QuestionPro CX is a dedicated customer experience suite for tracking Net Promoter Score, customer satisfaction, and journey feedback, separate from the core survey product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Who founded QuestionPro$q$, $q$QuestionPro was founded in 2005, originally headquartered in Seattle before later moving to San Francisco and then Austin, Texas.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Does QuestionPro offer academic or non-profit discounts$q$, $q$Yes, QuestionPro offers discounted rates for academic institutions and registered non-profit organizations.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Academic and multilingual market research$q$, $q$Researchers use QuestionPro to run large-scale studies across many countries and languages, relying on its extensive translation and localization support.$q$, $q$Academic researchers and market research agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Enterprise customer experience programs$q$, $q$CX teams use QuestionPro's dedicated suite to track Net Promoter Score, satisfaction, and customer journey feedback across touchpoints.$q$, $q$Customer experience and CX operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Employee engagement and workforce surveys$q$, $q$HR teams use QuestionPro's Workforce suite to run pulse and engagement surveys and track employee sentiment over time.$q$, $q$HR and people operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Essentials$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Core survey builder with 40-plus question types","Basic reporting","Limited response volume","Individual use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Team Edition$q$, $q$Approximately 83 US dollars per user per month$q$, $q$Annual, minimum 5 users$q$, NULL, $q$["Team collaboration","Advanced survey logic","Expanded reporting and analytics","Offline data collection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Advanced$q$, $q$Approximately 99 US dollars per user per month$q$, $q$Annual$q$, NULL, $q$["Advanced analytics and cross-tabulation","Expanded question types and logic","Priority support","Higher response limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Enterprise Suites (Research, CX, Workforce)$q$, $q$Custom - contact sales$q$, $q$Annual contract$q$, NULL, $q$["Dedicated market research, CX, or employee experience tools","Panel management","Custom integrations","Dedicated account support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuestionPro is an online survey and research platform founded in 2005 that has expanded well beyond basic survey creation into a family of specialized products covering market research, customer experience, and employee experience. Originally started in Seattle, the company later moved its headquarters to San Francisco before relocating its global headquarters to Austin, Texas, in 2020, and it now operates offices across the United States, India, Mexico, the United Arab Emirates, and Germany.$q$, $q$The platform is used by a wide range of customers, from individual researchers and students on its free tier to large enterprises running dedicated market research, customer experience, and workforce engagement programs through QuestionPro's specialized suites, which sit alongside its core survey-building tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its foundation, QuestionPro offers a drag-and-drop survey builder with more than 40 question types, branching and skip logic, and offline data collection for field-based research where internet access is unreliable. Reporting tools include cross-tabulation, advanced analytics, and customizable dashboards for turning raw responses into actionable findings.$q$, $q$One of QuestionPro's most distinctive strengths is language reach: the platform interface is localized in more than 230 languages, and survey content can be translated and collected in roughly 90 to 95 languages, including multi-byte character set languages like Chinese and Japanese and right-to-left languages such as Arabic and Hebrew, using either one-click automatic translation or professional translation services. Beyond core surveys, dedicated suites address market research and panel management (Research Suite), customer experience and NPS tracking (CX), and employee engagement (Workforce or EX).$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuestionPro offers a genuinely usable free Essentials plan intended for individuals and small, quick research projects, which is more feature-rich than many competitors' free tiers. Paid plans are priced per user: the Team Edition starts at roughly 83 US dollars per user per month when billed annually for organizations with five or more users, while the Advanced tier runs approximately 99 US dollars per user per month.$q$, $q$For organizations that need the specialized Research Suite, CX suite, or Workforce and Employee Experience suite, QuestionPro moves to custom enterprise pricing based on scope and requirements, quoted directly by its sales team. The company also offers discounted pricing for academic institutions and registered non-profit organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Double-entry bookkeeping and chart of accounts$q$, $q$Full general ledger accounting foundation used across all QuickBooks Desktop editions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Invoicing and estimates$q$, $q$Create and send customer invoices and estimates directly from the desktop application.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Inventory management$q$, $q$Track inventory levels, costs, and reordering in Premier and Enterprise editions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Industry-specific Enterprise editions$q$, $q$Specialized versions of QuickBooks Enterprise tailored to construction, manufacturing, retail, and nonprofit organizations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Multi-user network hosting$q$, $q$Multiple users can work in the same company file over a local network with defined permissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$1099 contractor tracking$q$, $q$Track and prepare 1099 forms for independent contractors directly within QuickBooks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Payroll integration$q$, $q$Add-on payroll processing that integrates with QuickBooks Desktop's accounting data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Detailed financial reporting$q$, $q$Extensive built-in reports covering profit and loss, balance sheets, and custom financial statements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Deep, mature feature set trusted by accountants and bookkeepers for decades$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Industry-specific Enterprise editions for construction, manufacturing, retail, and nonprofits$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Strong reporting depth compared to many lighter-weight accounting tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Large ecosystem of certified ProAdvisors and third-party integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Locally installed application appeals to businesses wanting data control outside a browser$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Multi-user network hosting supports in-office collaborative bookkeeping$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Pro Plus and Premier Plus are no longer sold to new customers as of October 2024$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Desktop pricing has risen sharply, with Pro Plus jumping to 1,149 US dollars per year in February 2026$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Only QuickBooks Enterprise remains available for new purchases, at a much higher price point$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Intuit's active development focus has shifted to QuickBooks Online, not Desktop$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Older Desktop versions lose support on a rolling schedule, requiring periodic paid upgrades$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Multi-user and per-employee payroll fees can add significant cost for growing teams$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Is QuickBooks Desktop still available$q$, $q$QuickBooks Desktop Pro Plus and Premier Plus are no longer sold to new customers as of after September 30, 2024, though existing subscribers can renew. QuickBooks Enterprise remains available for new purchases.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$What is the difference between QuickBooks and QuickBooks Online$q$, $q$QuickBooks refers to Intuit's broader accounting software brand, including the locally installed QuickBooks Desktop product line, while QuickBooks Online is the separate cloud-based, browser-accessible version with its own distinct pricing tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Who owns QuickBooks$q$, $q$QuickBooks is owned and developed by Intuit, a financial software company founded in 1983 and headquartered in Mountain View, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$When was QuickBooks founded$q$, $q$QuickBooks was first launched by Intuit in 1992 as DOS-based small business accounting software, following Intuit's founding in 1983.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Can I still buy QuickBooks Pro$q$, $q$No, new purchases of QuickBooks Pro Plus were discontinued after September 30, 2024. Existing Pro Plus subscribers can continue to renew, but new customers can only purchase QuickBooks Enterprise.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$What is QuickBooks Enterprise$q$, $q$QuickBooks Enterprise is the most advanced Desktop edition of QuickBooks, offering industry-specific versions, advanced inventory, and more granular permissions, and it is the only Desktop edition still sold to new customers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Does QuickBooks Desktop get replaced by QuickBooks Online$q$, $q$Intuit's active product development has shifted toward QuickBooks Online, and the company is encouraging Desktop customers to migrate, though Desktop editions, especially Enterprise, remain supported and sold.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Established small businesses with existing desktop workflows$q$, $q$Businesses already running their bookkeeping on QuickBooks Desktop continue using Pro Plus, Premier Plus, or Enterprise rather than migrating workflows to a browser-based tool.$q$, $q$Established small and midsize business owners and bookkeepers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Industry-specific accounting needs$q$, $q$Businesses in construction, manufacturing, retail, or nonprofit sectors use QuickBooks Enterprise's industry-specific editions for specialized reporting and workflows.$q$, $q$Construction, manufacturing, retail, and nonprofit finance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$Accounting firms managing legacy desktop clients$q$, $q$Bookkeeping and accounting firms maintain QuickBooks Desktop expertise to support existing clients still running Pro Plus or Premier Plus company files.$q$, $q$Accounting and bookkeeping firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$QuickBooks Pro Plus$q$, $q$1,149 US dollars per year (single user)$q$, $q$Annual$q$, NULL, $q$["Core bookkeeping and invoicing","1099 contractor tracking","No longer sold to new customers, renewal only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$QuickBooks Premier Plus$q$, $q$1,609 US dollars per year (single user); 345 US dollars per additional user$q$, $q$Annual$q$, NULL, $q$["Inventory management","Industry-specific reporting","No longer sold to new customers, renewal only"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$QuickBooks Enterprise Gold$q$, $q$Approximately 2,210 US dollars per year (single user)$q$, $q$Annual$q$, NULL, $q$["Advanced inventory","Industry-specific editions","Payroll add-on with per-employee fee"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$QuickBooks Enterprise Platinum$q$, $q$Approximately 2,717 US dollars per year$q$, $q$Annual$q$, NULL, $q$["All Gold features","Advanced pricing and inventory tools","Enhanced reporting"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$QuickBooks Enterprise Diamond$q$, $q$Custom, approximately 4,200-plus US dollars per year$q$, $q$Monthly billing$q$, NULL, $q$["All Platinum features","Assisted payroll included","Highest support tier"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuickBooks is the accounting software brand built by Intuit, the company founded in 1983 by Scott Cook and Tom Proulx and headquartered in Mountain View, California. QuickBooks launched in 1992 as DOS-based small business accounting software, expanded to Windows and Mac shortly afterward, and became the dominant small business accounting platform in the United States by the mid-2000s.$q$, $q$While QuickBooks Online has become Intuit's primary focus for new development, the QuickBooks brand also includes the original QuickBooks Desktop product line covering Pro Plus, Premier Plus, and Enterprise editions, which remains actively used by established small and midsize businesses, particularly those needing industry-specific editions or locally installed software rather than a browser-based tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuickBooks Desktop products offer double-entry bookkeeping, invoicing and estimates, bill payment and expense tracking, inventory management in Premier and Enterprise editions, and industry-specific editions of Enterprise built for sectors like construction, manufacturing, retail, and nonprofits. Desktop editions also support multi-user network hosting, detailed financial reporting, 1099 contractor tracking, and integration with Intuit's payroll and merchant payment services.$q$, $q$QuickBooks Enterprise, the only Desktop edition still sold to new customers, adds advanced inventory, more granular user permissions, and industry-specific reporting suited to larger and more complex small businesses. Across the QuickBooks brand, Intuit also maintains a large ecosystem of certified ProAdvisors, accountants, and third-party integrations built around QuickBooks data files and formats.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ae049dc-b6f0-4ae1-8fd5-b86fa82c3a82', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuickBooks Desktop is sold as annual subscriptions rather than the perpetual one-time licenses of the pre-2022 era. As of February 2026 pricing, single-user Pro Plus and Mac Plus cost 1,149 US dollars per year, up from 999 US dollars, while Premier Plus single-user pricing rose to 1,609 US dollars per year, with additional multi-user seats priced at 345 US dollars per user.$q$, $q$New Desktop customers can now only purchase QuickBooks Enterprise, which starts around 2,210 US dollars per year for the single-user Gold tier, approximately 2,717 US dollars per year for Platinum, and custom pricing above roughly 4,200 US dollars per year for the Diamond tier, billed monthly and including a per-employee payroll fee. Existing Pro Plus and Premier Plus subscribers can continue renewing even though new purchases were discontinued after September 30, 2024.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Cloud-based access from any device$q$, $q$Full accounting functionality accessible from a web browser or mobile app, with no local installation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Invoicing and sales tax automation$q$, $q$Create and send invoices with automatic sales tax calculation, available starting at the Simple Start tier.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Bank feed reconciliation$q$, $q$Automatically imports and categorizes bank and credit card transactions for faster reconciliation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Time tracking$q$, $q$Track billable and payroll hours directly within QuickBooks Online, available from the Essentials tier up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Inventory and project tracking$q$, $q$Monitor inventory levels and track project profitability, available starting at the Plus tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Class and location tracking$q$, $q$Segment income and expenses by department, location, or business unit for more granular reporting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Advanced custom reporting$q$, $q$Build tailored financial reports and dashboards, available at the Advanced tier for larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Third-party app marketplace integration$q$, $q$Connects with a wide ecosystem of payroll, payments, CRM, and e-commerce apps within the Intuit platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Accessible from any browser or device with no software installation required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Automatic updates mean features and compliance changes roll out continuously$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Tiered pricing scales cleanly from freelancers up to larger small businesses$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Deep integration with QuickBooks Payroll, Payments, and third-party apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Widely supported by accountants and bookkeepers familiar with the platform$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Real-time collaboration with employees and outside accountants without file sharing$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Prices have risen significantly year over year, with recent increases of 12 to 17 percent annually$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Essentials, Plus, and Advanced tiers cost meaningfully more than entry-level competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$User limits on lower tiers can force upgrades sooner than expected for growing teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Some advanced reporting and control features are reserved for the top Advanced tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Ongoing subscription cost over time can exceed what a one-time desktop license would have cost$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Introductory discounted pricing expires after a limited number of months$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$How much does QuickBooks Online cost$q$, $q$QuickBooks Online starts at 20 US dollars per month for the Solopreneur tier, with core plans running 38 US dollars per month for Simple Start, 75 US dollars for Essentials, 115 US dollars for Plus, and 275 US dollars per month for Advanced.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$What is the difference between Simple Start, Essentials, Plus, and Advanced$q$, $q$Simple Start covers single-user core accounting; Essentials adds time tracking and up to three users; Plus adds inventory, project tracking, and up to five users; Advanced adds higher user limits, advanced reporting, and stronger controls for larger businesses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$When did QuickBooks Online launch$q$, $q$Intuit first launched a cloud version of QuickBooks in 2001, though the product was substantially rebuilt in 2013, which is generally considered the turning point for QuickBooks Online's modern functionality.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Does QuickBooks Online raise prices every year$q$, $q$Yes, QuickBooks Online has typically raised prices about once a year, usually in the summer, with recent annual increases in the range of 12 to 17 percent since 2023.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Is there a free trial for QuickBooks Online$q$, $q$Intuit typically offers new subscribers either a free trial period or a discounted introductory rate for the first several months before standard pricing applies; specific current offers should be confirmed on the QuickBooks Online pricing page.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$How many users can use QuickBooks Online$q$, $q$User limits vary by tier: Simple Start supports one user, Essentials supports up to three, Plus supports up to five, and Advanced supports a higher number of users suited to larger businesses.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Is QuickBooks Online the same as QuickBooks Desktop$q$, $q$No. QuickBooks Online is a separate cloud-based, browser-accessible subscription product with its own pricing tiers, distinct from the locally installed QuickBooks Desktop product line.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Freelancers and sole proprietors$q$, $q$Independent freelancers use the Solopreneur tier to track income, expenses, and estimated taxes without needing full small business accounting features.$q$, $q$Freelancers, gig workers, and sole proprietors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Small business day-to-day bookkeeping$q$, $q$Small businesses use Simple Start or Essentials for invoicing, expense tracking, and bank reconciliation from any device.$q$, $q$Small business owners and bookkeepers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Growing businesses with inventory and multiple users$q$, $q$Businesses managing inventory, projects, and multiple team members use the Plus or Advanced tiers for deeper tracking and reporting.$q$, $q$Growing small and midsize businesses with multiple employees$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Solopreneur$q$, $q$20 US dollars per month$q$, $q$Monthly$q$, NULL, $q$["Income and expense tracking","Basic invoicing","Estimated quarterly tax tracking","Mileage tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Simple Start$q$, $q$38 US dollars per month$q$, $q$Monthly$q$, NULL, $q$["Full invoicing","Sales tax automation","Bill management","1099 contractor tracking","Single user"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Essentials$q$, $q$75 US dollars per month$q$, $q$Monthly$q$, NULL, $q$["Everything in Simple Start","Time tracking","Up to 3 users","Bill management workflow"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Plus$q$, $q$115 US dollars per month$q$, $q$Monthly$q$, NULL, $q$["Everything in Essentials","Inventory tracking","Project profitability tracking","Purchase orders and budgets","Class and location tracking","Up to 5 users"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Advanced$q$, $q$275 US dollars per month$q$, $q$Monthly$q$, NULL, $q$["Everything in Plus","Higher user limits","Advanced custom reporting","Higher transaction volume support","Stronger controls and permissions"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuickBooks Online is Intuit's cloud-based accounting product, accessible from any web browser or the QuickBooks mobile app rather than installed locally on a single machine. Intuit first introduced a cloud version of QuickBooks in 2001, though the early product was limited compared to the desktop software; a substantial rebuild in 2013 turned QuickBooks Online into the fully featured, actively developed product it is today, and it is now Intuit's primary focus for accounting software development.$q$, $q$Unlike QuickBooks Desktop, which is licensed annually per installation, QuickBooks Online is a straightforward monthly SaaS subscription with automatic updates, anywhere access, and tiers that scale by feature set and number of users rather than by installed workstation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuickBooks Online covers core small business accounting needs including invoicing, expense and bill tracking, bank feed reconciliation, sales tax automation, and 1099 contractor tracking, available even at the entry-level Simple Start tier. Higher tiers add time tracking (Essentials), inventory management, project profitability tracking, purchase orders, budgeting, and class or location tracking (Plus), and more advanced custom reporting, higher user limits, and stronger internal controls (Advanced).$q$, $q$Because it runs in the cloud, QuickBooks Online integrates natively with Intuit's broader ecosystem, including QuickBooks Payments, QuickBooks Payroll, and a large marketplace of third-party app integrations, and it supports real-time collaboration between business owners, employees, and outside accountants or bookkeepers without needing to share a local company file.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuickBooks Online is priced across five tiers: Solopreneur at 20 US dollars per month for freelancers, Simple Start at 38 US dollars per month for single-user small businesses, Essentials at 75 US dollars per month supporting up to three users with time tracking, Plus at 115 US dollars per month supporting up to five users with inventory and project tracking, and Advanced at 275 US dollars per month for larger businesses needing more users, higher transaction volumes, and advanced reporting.$q$, $q$QuickBooks Online has historically raised prices roughly once a year, typically in the summer, with recent annual increases ranging from about 12 to 17 percent since 2023, and new subscribers commonly receive a discounted introductory rate for the first several months before the standard monthly price takes effect.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$GPS-enabled mobile time tracking$q$, $q$Employees clock in and out from their mobile devices with GPS location tagging for field and remote work verification.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Geofencing reminders$q$, $q$Automatically prompts employees to clock in or out when they enter or leave a defined job site location.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Employee scheduling$q$, $q$Build and share work schedules and shift assignments directly within the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Overtime alerts$q$, $q$Notifies managers when employees approach or exceed overtime thresholds to help control labor costs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Project time tracking$q$, $q$Tracks time against specific projects or jobs, available with enhanced detail on the Elite tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Real-time project collaboration$q$, $q$Elite-tier feature enabling teams to coordinate on project time and status in real time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$QuickBooks Online and Payroll integration$q$, $q$Time data flows directly into QuickBooks Online and QuickBooks Payroll for streamlined payroll processing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Free admin license$q$, $q$Both Premium and Elite plans include one complimentary administrator seat.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Native, tight integration with QuickBooks Online and QuickBooks Payroll$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$GPS and geofencing features well suited to field service and mobile workforces$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Scheduling and time tracking combined in a single product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Overtime alerts help control unplanned labor costs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Free admin license included on both pricing tiers$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Backed by Intuit's scale and long-term product investment since the 2018 acquisition$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Requires an active QuickBooks Online subscription to use, adding to total cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Per-user pricing increased in July 2026, raising ongoing costs for existing customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Elite tier's advanced project collaboration features come at a notable price premium$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Less useful as a standalone product outside the QuickBooks ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Base fee plus per-user pricing can add up quickly for larger hourly workforces$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Feature parity with dedicated standalone scheduling tools varies by tier$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$How much does QuickBooks Time cost$q$, $q$As of 2026, QuickBooks Time Premium costs 20 US dollars per month plus 10 US dollars per active user per month, and Elite costs 40 US dollars per month plus 12 US dollars per active user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$What was QuickBooks Time called before$q$, $q$QuickBooks Time was previously known as TSheets, an independent company founded in 2006 in Eagle, Idaho, which Intuit acquired in a deal that closed in January 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Do I need QuickBooks Online to use QuickBooks Time$q$, $q$Yes, a QuickBooks Online subscription is required to use QuickBooks Time, since the two products are designed to work together.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$What is the difference between QuickBooks Time Premium and Elite$q$, $q$Premium focuses on attendance tracking and basic scheduling, while Elite adds advanced project time tracking and real-time project collaboration features for a higher price.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Does QuickBooks Time support GPS tracking$q$, $q$Yes, QuickBooks Time offers GPS-enabled mobile time tracking and geofencing that can prompt automatic clock-in and clock-out reminders based on location.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$When did Intuit acquire TSheets$q$, $q$Intuit announced its acquisition of TSheets on December 5, 2017, in a deal valued at roughly 340 million US dollars, and the acquisition closed on January 11, 2018.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Is there a free admin account with QuickBooks Time$q$, $q$Yes, both the Premium and Elite plans include one free administrator license.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Field service and mobile workforce time tracking$q$, $q$Field service companies use GPS-enabled clock-in and geofencing to accurately track hours for employees working across multiple job sites.$q$, $q$Field service, construction, and trade businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Payroll-integrated hourly workforce management$q$, $q$Businesses already using QuickBooks Online and Payroll use QuickBooks Time to eliminate manual timesheet entry and streamline payroll runs.$q$, $q$Small business owners managing hourly employees$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Project-based time and labor cost tracking$q$, $q$Project-driven businesses use the Elite tier's project time tracking to monitor labor costs and collaboration in real time against specific jobs.$q$, $q$Project-based businesses such as contractors and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Premium$q$, $q$20 US dollars per month base plus 10 US dollars per active user per month$q$, $q$Monthly$q$, NULL, $q$["GPS mobile time tracking","Scheduling","Overtime alerts","One free admin license","QuickBooks Online integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$Elite$q$, $q$40 US dollars per month base plus 12 US dollars per active user per month$q$, $q$Monthly$q$, NULL, $q$["Everything in Premium","Advanced project time tracking","Real-time project collaboration","Enhanced geofencing precision","One free admin license"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuickBooks Time is Intuit's employee time tracking and scheduling product, known for most of its history as TSheets. TSheets was founded in 2006 in Eagle, Idaho by CEO Matt Rissell and grew into a significant independent time-tracking company before Intuit acquired it in a deal announced in December 2017 and valued at roughly 340 million US dollars, closing in January 2018.$q$, $q$After the acquisition, the product was gradually rebranded from TSheets by QuickBooks to its current name, QuickBooks Time, and it now operates as a dedicated time tracking and scheduling companion to QuickBooks Online and QuickBooks Payroll, rather than as a standalone accounting product. It remains focused specifically on time tracking, scheduling, and related workforce management rather than broader bookkeeping.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuickBooks Time offers GPS-enabled mobile time tracking so field and remote employees can clock in and out from job sites using their phones, along with geofencing that can prompt automatic clock-in and clock-out reminders based on an employee's location. Scheduling tools let managers build and share employee schedules and available shifts, and overtime alerts help prevent unplanned labor cost overruns.$q$, $q$The Elite tier adds more advanced project time tracking and real-time project collaboration features aimed at businesses managing multiple concurrent jobs or projects, while both tiers feed time data directly into QuickBooks Online and QuickBooks Payroll to streamline payroll processing and eliminate manual timesheet entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b5f7e26c-b483-4bd7-8ac4-22126346a402', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuickBooks Time is sold in two tiers, each combining a flat monthly base fee with a per-active-user monthly fee. As of current 2026 pricing, following a rate increase implemented around July 1, 2026, the Premium plan costs 20 US dollars per month base plus 10 US dollars per active user per month, and the Elite plan costs 40 US dollars per month base plus 12 US dollars per active user per month.$q$, $q$Both plans include one free admin license, and a QuickBooks Online subscription is required alongside QuickBooks Time, since the two products are sold and used together rather than fully independently. The July 2026 price increase raised per-user fees by roughly 2 US dollars per user across both tiers compared to prior pricing.$q$]::text[], 2);
